class TrieNode:
    __slots__ = ('ch', 'end')
    def __init__(self):
        self.ch = {}
        self.end = False

class Trie:
    def __init__(self):
        self.root = TrieNode()
    def insert(self, word: str) -> None:
        node = self.root
        for c in word:
            node = node.ch.setdefault(c, TrieNode())
        node.end = True
    def search(self, word: str) -> bool:
        node = self.root
        for c in word:
            if c not in node.ch: return False
            node = node.ch[c]
        return node.end
    def startsWith(self, prefix: str) -> bool:
        node = self.root
        for c in prefix:
            if c not in node.ch: return False
            node = node.ch[c]
        return True

